-- ============================================================
-- fn_CleanString
-- Technické čištění řetězce - univerzální základ
--
-- Odstraňuje:
--   • Control chars ASCII 1-31
--   • DEL (127)
--   • NBSP (160)           → mezera (pak sloučena)
--   • Zero-width space (8203)
--   • Zero-width no-break space / BOM (65279)
--   • Soft hyphen (173)    → odstraněn (ne nahrazen)
--   • Vícenásobné mezery   → jedna mezera
--   • Trim
--   • Prázdný výsledek     → NULL
--
-- Nezasahuje do: interpunkce, závorek, pomlček, teček,
--               speciálních znaků URL/email/tel
-- ============================================================
CREATE   FUNCTION [dbo].[fn_CleanString]
(
    @val NVARCHAR(500)
)
RETURNS NVARCHAR(500)
AS
BEGIN
    IF @val IS NULL RETURN NULL;

    DECLARE @result NVARCHAR(500) = @val;
    DECLARE @i INT = 1;

    -- Control chars 1-31
    WHILE @i <= 31
    BEGIN
        SET @result = REPLACE(@result, NCHAR(@i), N'');
        SET @i += 1;
    END

    -- DEL
    SET @result = REPLACE(@result, NCHAR(127),  N'');

    -- NBSP → mezera (sloučí se níže)
    SET @result = REPLACE(@result, NCHAR(160),  N' ');

    -- Soft hyphen → odstranit
    SET @result = REPLACE(@result, NCHAR(173),  N'');

    -- Zero-width space → odstranit
    SET @result = REPLACE(@result, NCHAR(8203), N'');

    -- Zero-width no-break space / BOM → odstranit
    SET @result = REPLACE(@result, NCHAR(65279), N'');

    -- Sloučit vícenásobné mezery
    WHILE CHARINDEX(N'  ', @result) > 0
        SET @result = REPLACE(@result, N'  ', N' ');

    SET @result = LTRIM(RTRIM(@result));

    IF LEN(@result) = 0 RETURN NULL;

    RETURN @result;
END

-- ============================================================
-- fn_NormalizeEmail  (v2)
-- Normalizuje jeden emailový řetězec dle RFC 5321 / RFC 5322
--
-- Parametry:
--   @input      - jeden token (výstup fn_SplitContacts)
--   @importAsIs - 1 = jen fn_CleanString + lowercase, bez validace
--                 0 = plná normalizace + validace (výchozí)
--
-- Vrací:
--   Normalizovaný email (lowercase, trimovaný, RFC čištění)
--   NULL pokud:
--     • vstup je prázdný/NULL
--     • neobsahuje právě jedno @
--     • local část je po čištění prázdná
--     • local část obsahuje dvě tečky za sebou (..)
--     • domain část neobsahuje tečku / začíná nebo končí tečkou
--     • TLD kratší než 2 znaky nebo obsahuje nečíselné znaky
--
-- RFC 5321 local část:
--   Povolené znaky: a-z 0-9 ! # $ % & ' * + - / = ? ^ _ ` { | } ~ .
--   Tečka: nesmí být první, poslední ani zdvojená
--   Znaky mimo tuto množinu na začátku jsou ořezány
--
-- Poznámka:
--   Funkce nefiltruje placeholder emaily (info@, admin@ atd.)
--   Parametr @importAsIs připraven na budoucí cfg_NormRules
-- ============================================================
CREATE   FUNCTION [dbo].[fn_NormalizeEmail]
(
    @input      NVARCHAR(500),
    @importAsIs BIT = 0
)
RETURNS NVARCHAR(500)
AS
BEGIN
    IF @input IS NULL RETURN NULL;

    -- Krok 1: technické čištění + lowercase
    DECLARE @clean NVARCHAR(500) = LOWER([dbo].[fn_CleanString](@input));
    IF @clean IS NULL RETURN NULL;

    -- ImportAsIs: vrátit vyčištěný lowercase string bez validace
    IF @importAsIs = 1 RETURN @clean;

    -- Krok 2: Ověřit právě jedno @
    DECLARE @at_count INT =
        LEN(@clean) - LEN(REPLACE(@clean, N'@', N''));
    IF @at_count <> 1 RETURN NULL;

    -- Krok 3: Rozdělit na local a domain části
    DECLARE @at_pos INT = CHARINDEX(N'@', @clean);
    DECLARE @local  NVARCHAR(200) = LEFT(@clean, @at_pos - 1);
    DECLARE @domain NVARCHAR(300) = SUBSTRING(@clean, @at_pos + 1, LEN(@clean));

    -- Krok 4: Čištění local části
    -- Ořezat úvodní znaky které nejsou v RFC 5321 množině
    -- Povolené: a-z 0-9 ! # $ % & ' * + - / = ? ^ _ ` { | } ~ .
    -- Nepovolené na začátku jsou ořezány dokud nenarazíme na platný znak
    WHILE LEN(@local) > 0
    BEGIN
        DECLARE @first NCHAR(1) = LEFT(@local, 1);

        -- Tečka na začátku → ořezat vždy (RFC zakazuje)
        IF @first = N'.' BEGIN SET @local = SUBSTRING(@local, 2, LEN(@local)); CONTINUE; END

        -- Povolené RFC znaky na začátku: písmena, číslice a vybrané speciální
        -- Používáme explicitní testy místo LIKE (+ a _ mají v LIKE speciální význam)
        IF @first LIKE N'[a-z]' COLLATE Latin1_General_CI_AS BREAK;
        IF @first LIKE N'[0-9]' COLLATE Latin1_General_CI_AS BREAK;
        -- Povolené speciální znaky dle RFC 5321 které smí být na začátku
        IF @first IN (N'!', N'#', N'$', N'%', N'&', N'''', N'*',
                      N'+', N'-', N'/', N'=', N'?', N'^', N'_',
                      N'`', N'{', N'|', N'}', N'~') BREAK;

        -- Cokoliv jiného → ořezat
        SET @local = SUBSTRING(@local, 2, LEN(@local));
    END

    -- Ořezat tečky na konci local části
    WHILE LEN(@local) > 0 AND RIGHT(@local, 1) = N'.'
        SET @local = LEFT(@local, LEN(@local) - 1);

    -- Local část nesmí být prázdná
    IF LEN(@local) = 0 RETURN NULL;

    -- Local část nesmí obsahovat dvě tečky za sebou
    IF CHARINDEX(N'..', @local) > 0 RETURN NULL;

    -- Krok 5: Validace domain části
    IF LEN(@domain) = 0 RETURN NULL;

    -- Doména nesmí začínat nebo končit tečkou
    IF LEFT(@domain, 1) = N'.' RETURN NULL;
    IF RIGHT(@domain, 1) = N'.' RETURN NULL;

    -- Doména musí obsahovat alespoň jednu tečku
    IF CHARINDEX(N'.', @domain) = 0 RETURN NULL;

    -- TLD (část za poslední tečkou) musí mít min 2 znaky
    DECLARE @last_dot INT =
        LEN(@domain) - CHARINDEX(N'.', REVERSE(@domain)) + 1;
    DECLARE @tld NVARCHAR(20) =
        SUBSTRING(@domain, @last_dot + 1, LEN(@domain));
    IF LEN(@tld) < 2 RETURN NULL;

    -- TLD musí obsahovat pouze písmena
    IF @tld LIKE N'%[^a-z]%' RETURN NULL;

    RETURN @local + N'@' + @domain;
END

-- ============================================================
-- fn_NormalizePhone
-- Normalizuje jedno telefonní číslo do formátu E.164
--
-- Parametry:
--   @input      - jeden token (výstup fn_SplitContacts)
--   @defaultCC  - výchozí předvolba BEZ + a BEZ nul, např. '420'
--                 NULL = nepřidávat předvolbu pokud chybí
--   @importAsIs - 1 = jen fn_CleanString, bez normalizace
--                 0 = plná normalizace (výchozí)
--
-- Vrací:
--   E.164 formát: +420603111111
--   NULL pokud:
--     • vstup je prázdný/NULL
--     • číslo nevyhoví validaci délky
--     • chybí předvolba a @defaultCC je NULL
--     • @importAsIs = 1 → vrací vyčištěný raw string (ne NULL)
--
-- Validace délky (počet číslic včetně předvolby):
--   Minimálně 7 číslic, maximálně 15 číslic (ITU-T E.164 max)
--
-- Poznámka k rozšíření:
--   Parametry jsou připraveny na budoucí tabulku pravidel
--   cfg_NormRules - orchestrace předá @defaultCC a @importAsIs
--   podle pravidel pro daný zdroj/zemi, funkce zůstane beze změny
-- ============================================================
CREATE   FUNCTION [dbo].[fn_NormalizePhone]
(
    @input      NVARCHAR(100),
    @defaultCC  VARCHAR(5) = NULL,
    @importAsIs BIT        = 0
)
RETURNS NVARCHAR(20)
AS
BEGIN
    IF @input IS NULL RETURN NULL;

    -- Krok 1: technické čištění
    DECLARE @clean NVARCHAR(100) = [dbo].[fn_CleanString](@input);
    IF @clean IS NULL RETURN NULL;

    -- ImportAsIs: vrátit vyčištěný string bez normalizace
    IF @importAsIs = 1 RETURN @clean;

    -- Krok 2: Odstranit formátovací znaky
    -- závorky, pomlčky, tečky, lomítka, mezery
    DECLARE @stripped NVARCHAR(100) = @clean;
    SET @stripped = REPLACE(@stripped, N'(',  N'');
    SET @stripped = REPLACE(@stripped, N')',  N'');
    SET @stripped = REPLACE(@stripped, N'-',  N'');
    SET @stripped = REPLACE(@stripped, N'.',  N'');
    SET @stripped = REPLACE(@stripped, N'/',  N'');
    SET @stripped = REPLACE(@stripped, N' ',  N'');

    IF LEN(@stripped) = 0 RETURN NULL;

    -- Krok 3: Normalizace předvolby
    DECLARE @normalized NVARCHAR(20);

    IF LEFT(@stripped, 1) = N'+'
    BEGIN
        -- Má explicitní + → zachovat jak je
        SET @normalized = @stripped;
    END
    ELSE IF LEFT(@stripped, 2) = N'00'
    BEGIN
        -- 00XX → +XX
        SET @normalized = N'+' + SUBSTRING(@stripped, 3, LEN(@stripped));
    END
    ELSE
    BEGIN
        -- Nemá předvolbu
        IF @defaultCC IS NOT NULL
            SET @normalized = N'+' + @defaultCC + @stripped;
        ELSE
            RETURN NULL;  -- nehádat předvolbu
    END

    -- Krok 4: Ověřit že za + jsou jen číslice
    DECLARE @digits NVARCHAR(20) = SUBSTRING(@normalized, 2, LEN(@normalized));
    IF @digits LIKE N'%[^0-9]%' RETURN NULL;

    -- Krok 5: Validace délky
    -- Celkový počet číslic (bez +): min 7, max 15 (E.164)
    DECLARE @digit_count INT = LEN(@digits);
    IF @digit_count < 7  RETURN NULL;
    IF @digit_count > 15 RETURN NULL;

    RETURN @normalized;
END

-- ============================================================
-- fn_NormalizeUrl
-- Normalizuje URL adresu
--
-- Parametry:
--   @input      - vstupní řetězec
--   @importAsIs - 1 = jen fn_CleanString + lowercase, bez normalizace
--                 0 = plná normalizace + validace (výchozí)
--
-- Vrací:
--   Normalizovanou URL (lowercase, https://, bez trailing /)
--   NULL pokud:
--     • vstup je prázdný/NULL
--     • schéma není http:// nebo https:// (po doplnění)
--     • doména neobsahuje tečku
--     • TLD kratší než 2 znaky nebo obsahuje nealfabetické znaky
--     • URL obsahuje mezery (po vyčištění)
--
-- Normalizace:
--   • Markdown [text](url)        → extrahovat jen URL
--   • začíná www. nebo bez schématu → doplnit https://
--   • http://                     → zachovat (může být záměrné)
--   • trailing /                  → odstranit
--   • ftp:// a jiná schémata      → NULL
--
-- Poznámka:
--   Funkce neověřuje existenci/dostupnost webu
--   Parametr @importAsIs připraven na budoucí cfg_NormRules
-- ============================================================
CREATE   FUNCTION [dbo].[fn_NormalizeUrl]
(
    @input      NVARCHAR(500),
    @importAsIs BIT = 0
)
RETURNS NVARCHAR(500)
AS
BEGIN
    IF @input IS NULL RETURN NULL;

    -- Krok 1: technické čištění + lowercase
    DECLARE @clean NVARCHAR(500) = LOWER([dbo].[fn_CleanString](@input));
    IF @clean IS NULL RETURN NULL;

    -- ImportAsIs: vrátit vyčištěný lowercase string bez normalizace
    IF @importAsIs = 1 RETURN @clean;

    -- Krok 2: Extrahovat URL z markdown formátu [text](url)
    -- Vzor: [cokoliv](url) → url
    DECLARE @md_start INT = CHARINDEX(N'](', @clean);
    IF @md_start > 0
    BEGIN
        DECLARE @url_start INT = @md_start + 2;
        DECLARE @url_end   INT = CHARINDEX(N')', @clean, @url_start);
        IF @url_end > @url_start
            SET @clean = SUBSTRING(@clean, @url_start, @url_end - @url_start);
        ELSE
            SET @clean = SUBSTRING(@clean, @url_start, LEN(@clean));
    END

    -- Trim po extrakci
    SET @clean = LTRIM(RTRIM(@clean));
    IF LEN(@clean) = 0 RETURN NULL;

    -- Krok 3: Nesmí obsahovat mezery
    IF CHARINDEX(N' ', @clean) > 0 RETURN NULL;

    -- Krok 4: Normalizace schématu
    IF LEFT(@clean, 8)  = N'https://'
        SET @clean = @clean;  -- ok
    ELSE IF LEFT(@clean, 7) = N'http://'
        SET @clean = @clean;  -- ok, zachovat
    ELSE IF LEFT(@clean, 4) = N'www.'
        SET @clean = N'https://' + @clean;
    ELSE IF CHARINDEX(N'://', @clean) > 0
        -- Jiné schéma (ftp://, mailto:// atd.) → NULL
        RETURN NULL;
    ELSE
        -- Bez schématu, bez www → doplnit https://
        SET @clean = N'https://' + @clean;

    -- Krok 5: Extrahovat doménu (část mezi :// a prvním / nebo koncem)
    DECLARE @domain_start INT = CHARINDEX(N'://', @clean) + 3;
    DECLARE @domain_end   INT = CHARINDEX(N'/', @clean, @domain_start);
    DECLARE @domain NVARCHAR(200);

    IF @domain_end > 0
        SET @domain = SUBSTRING(@clean, @domain_start, @domain_end - @domain_start);
    ELSE
        SET @domain = SUBSTRING(@clean, @domain_start, LEN(@clean));

    -- Odstranit port pokud je přítomen (domain:8080 → domain)
    DECLARE @port_pos INT = CHARINDEX(N':', @domain);
    IF @port_pos > 0
        SET @domain = LEFT(@domain, @port_pos - 1);

    IF LEN(@domain) = 0 RETURN NULL;

    -- Krok 6: Validace domény
    -- Nesmí začínat nebo končit tečkou
    IF LEFT(@domain, 1)  = N'.' RETURN NULL;
    IF RIGHT(@domain, 1) = N'.' RETURN NULL;

    -- Musí obsahovat alespoň jednu tečku
    IF CHARINDEX(N'.', @domain) = 0 RETURN NULL;

    -- TLD validace
    DECLARE @last_dot INT =
        LEN(@domain) - CHARINDEX(N'.', REVERSE(@domain)) + 1;
    DECLARE @tld NVARCHAR(20) =
        SUBSTRING(@domain, @last_dot + 1, LEN(@domain));
    IF LEN(@tld) < 2 RETURN NULL;
    IF @tld LIKE N'%[^a-z]%' COLLATE Latin1_General_CI_AS RETURN NULL;

    -- Krok 7: Odstranit trailing / na konci celé URL
    WHILE RIGHT(@clean, 1) = N'/'
        SET @clean = LEFT(@clean, LEN(@clean) - 1);

    RETURN @clean;
END

-- ============================================================
-- fn_SplitContacts
-- Rozdělí vícehodnotové pole na jednotlivé tokeny
--
-- Parametry:
--   @val        - vstupní řetězec (telefony, emaily, ...)
--   @delimiters - řetězec oddělovačů, každý znak = jeden oddělovač
--                 např. ';,'  nebo  ';'
--
-- Vrací:
--   Poradi      - pořadí tokenu (1, 2, 3...)
--   Hodnota     - jeden token, trimovaný, neprázdný
--
-- Volání:
--   CROSS APPLY infobase.dbo.fn_SplitContacts(d.D_Tel, ';,')
--   CROSS APPLY infobase.dbo.fn_SplitContacts(d.D_Email, ';')
--
-- Poznámky:
--   • Mezera NENÍ oddělovač - číslo '+420 731 173 068' zůstane celé
--   • Prázdné tokeny jsou přeskočeny
--   • Funkce nevolá fn_CleanString - to je zodpovědnost volajícího
-- ============================================================
CREATE   FUNCTION [dbo].[fn_SplitContacts]
(
    @val        NVARCHAR(1000),
    @delimiters NVARCHAR(20)
)
RETURNS @result TABLE
(
    Poradi  INT,
    Hodnota NVARCHAR(500)
)
AS
BEGIN
    IF @val IS NULL OR LEN(LTRIM(RTRIM(@val))) = 0
        RETURN;

    -- Nahradit všechny oddělovače pipe-znakem |
    DECLARE @normalized NVARCHAR(1000) = @val;
    DECLARE @i INT = 1;
    DECLARE @delim_len INT = LEN(@delimiters);

    WHILE @i <= @delim_len
    BEGIN
        SET @normalized = REPLACE(
            @normalized,
            SUBSTRING(@delimiters, @i, 1),
            N'|'
        );
        SET @i += 1;
    END

    -- Přidat | na konec pro jednotný parsing
    SET @normalized = @normalized + N'|';

    -- Splitovat podle |
    DECLARE @poradi  INT = 0;
    DECLARE @pos     INT;
    DECLARE @token   NVARCHAR(500);

    WHILE LEN(@normalized) > 0
    BEGIN
        SET @pos = CHARINDEX(N'|', @normalized);
        IF @pos = 0 BREAK;

        SET @token = LTRIM(RTRIM(SUBSTRING(@normalized, 1, @pos - 1)));
        SET @normalized = SUBSTRING(@normalized, @pos + 1, LEN(@normalized));

        -- Přeskočit prázdné tokeny
        IF LEN(@token) = 0 CONTINUE;

        SET @poradi += 1;
        INSERT @result (Poradi, Hodnota) VALUES (@poradi, @token);
    END

    RETURN;
END
